resource "aws_iam_role_policy" "flow_log" {
  name   = "${local.name_prefix}-vpc-flow-log-write"
  role   = aws_iam_role.flow_log.id
  policy = data.aws_iam_policy_document.flow_log_write.json
}

resource "aws_iam_role_policy" "flow_log" {
  name   = "${local.name_prefix}-vpc-flow-log-write"
  role   = aws_iam_role.flow_log.id
  policy = data.aws_iam_policy_document.flow_log_write.json
